      | READY -> "READY"
      | FAILED -> "FAILED"
      | SYNCHRONIZING -> "SYNCHRONIZING"
      | SYNCHRONIZE_UNSUCCESSFUL -> "SYNCHRONIZE_UNSUCCESSFUL"
      | CREATE_PENDING_AUTH -> "CREATE_PENDING_AUTH"
