      | "UPDATE_UNSUCCESSFUL" -> UPDATE_UNSUCCESSFUL
      | "DELETING" -> DELETING
      | "READY" -> READY
      | "FAILED" -> FAILED
      | "SYNCHRONIZING" -> SYNCHRONIZING
      | "SYNCHRONIZE_UNSUCCESSFUL" -> SYNCHRONIZE_UNSUCCESSFUL
